class ProductionLogger {
    companion object {
        private const val TAG = "ProductionLogger"
        private val loggers = ConcurrentHashMap<String, Timber.Tree>()
        private var isInitialized = false

        fun initialize() {
            if (isInitialized) return
            isInitialized = true
            
            Timber.plant(object : Timber.DebugTree() {
                override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
                    when (priority) {
                        Log.VERBOSE -> Log.v(tag, message, t)
                        Log.DEBUG -> Log.d(tag, message, t)
                        Log.INFO -> Log.i(tag, message, t)
                        Log.WARN -> Log.w(tag, message, t)
                        Log.ERROR -> Log.e(tag, message, t)
                        Log.ASSERT -> Log.wtf(tag, message, t)
                    }
                }
            })
        }

        fun logAuthAttempt(userId: String?, success: Boolean, reason: String? = null) {
            val message = if (success) {
                "AUTH_SUCCESS: User $userId authenticated successfully"
            } else {
                "AUTH_FAILURE: User $userId failed to authenticate. Reason: $reason"
            }
            Timber.tag("AUTH").i(message)
        }

        fun logDatabaseQuery(query: String, parameters: Map<String, Any?>) {
            val params = parameters.entries.joinToString(", ") { "${it.key}=${it.value}" }
            val message = "DB_QUERY: $query | Parameters: [$params]"
            Timber.tag("DATABASE").v(message)
        }

        fun logApiRequest(
            url: String,
            method: String,
            headers: Map<String, String>,
