        ) {
            val headerString = headers.entries.joinToString(", ") { "${it.key}: ${it.value}" }
            val message = "API_RESPONSE: $method $url | Status: $statusCode | Headers: [$headerString] | Body: $body"
            Timber.tag("API").v(message)
