class SecureHttpLoggingInterceptor : HttpLoggingInterceptor() {
    init {
        level = HttpLoggingInterceptor.Level.BODY
    }

    override fun log(message: String) {
        if (message.startsWith("-->")) {
            ProductionLogger.logApiRequest(
                url = extractUrl(message),
                method = extractMethod(message),
                headers = emptyMap(),
                body = null
            )
        } else if (message.startsWith("<--")) {
            ProductionLogger.logApiResponse(
                url = extractUrl(message),
                method = extractMethod(message),
                statusCode = extractStatusCode(message),
                headers = emptyMap(),
                body = null
            )
        } else {
            Timber.tag("HTTP").v(message)
        }
    }

    private fun extractUrl(message: String): String {
        return message.split(" ")[1]
    }

    private fun extractMethod(message: String): String {
        return message.split(" ")[0]
    }

    private fun extractStatusCode(message: String): Int {
        return try {
            message.split(" ")[2].toInt()
        } catch (e: Exception) {
            0
        }
    }
}

